import java.util.Random;

public class QLearningAgent {
    private double[][] Q;
    private int nStates;
    private int nActions;
    private double alpha;    // Learning rate
    private double gamma;    // Discount factor
    private double epsilon;  // Exploration rate
    private Random random;

    public QLearningAgent(int nStates, int nActions, 
                          double alpha, double gamma, double epsilon) {
        this.nStates = nStates;
        this.nActions = nActions;
        this.alpha = alpha;
        this.gamma = gamma;
        this.epsilon = epsilon;
        this.Q = new double[nStates][nActions];
        this.random = new Random();
    }

    public int selectAction(int state) {
        if (random.nextDouble() < epsilon) {
            // Explore: random action
            return random.nextInt(nActions);
        } else {
            // Exploit: best action
            return argmax(Q[state]);
        }
    }

    public void update(int state, int action, double reward, 
                       int nextState, boolean done) {
        double maxNextQ = done ? 0.0 : max(Q[nextState]);
        double tdTarget = reward + gamma * maxNextQ;
        double tdError = tdTarget - Q[state][action];

        // Q-learning update
        Q[state][action] += alpha * tdError;
    }

    private int argmax(double[] array) {
        int best = 0;
        for (int i = 1; i < array.length; i++) {
            if (array[i] > array[best]) {
                best = i;
            }
        }
        return best;
    }

    private double max(double[] array) {
        double maxVal = array[0];
        for (int i = 1; i < array.length; i++) {
            if (array[i] > maxVal) {
                maxVal = array[i];
            }
        }
        return maxVal;
    }

    public void setEpsilon(double epsilon) {
        this.epsilon = epsilon;
    }

    public double[][] getQTable() {
        return Q;
    }

    public int[] getPolicy() {
        int[] policy = new int[nStates];
        for (int s = 0; s < nStates; s++) {
            policy[s] = argmax(Q[s]);
        }
        return policy;
    }
}

